SELECT RQHD.BUYER_CD , RQHD.DEPT_CD , GETBUYERDEPTNAME(RQHD.GATE_CD, RQHD.BUYER_CD, RQHD.DEPT_CD, #{ses.langCd}) AS BUYER_DEPT_NM , RQHD.PROGRESS_CD , RQHD.RFX_NUM , RQHD.RFX_CNT AS ORI_RFX_CNT -- 원본 견적차수 , RQHD.RFX_TYPE , GETCODENAME(RQHD.GATE_CD, 'M070', RQHD.RFX_TYPE, #{ses.langCd}) AS RFX_TYPE_NM , RQHD.RFX_LIMIT_CNT , RQHD.RFX_SUBJECT , (RQHD.RFX_START_DATE, 'YYYY-MM-DD') AS RFX_START_DATE , (RQHD.RFX_START_DATE, 'HH24') AS RFX_START_HOUR , (RQHD.RFX_START_DATE, 'MI') AS RFX_START_MIN , (RQHD.RFX_END_DATE, 'YYYY-MM-DD') AS RFX_CLOSE_DATE , (RQHD.RFX_END_DATE, 'HH24') AS RFX_CLOSE_HOUR , (RQHD.RFX_END_DATE, 'MI') AS RFX_CLOSE_MIN , RQHD.CTRL_USER_ID , GETUSERNAME(RQHD.GATE_CD, RQHD.CTRL_USER_ID, #{ses.langCd}) AS CTRL_USER_NM , GETUSERINFO(RQHD.GATE_CD, RQHD.CTRL_USER_ID, 'USER_TYPE') AS CTRL_USER_TYPE , RQHD.ESTM_USER_ID , GETUSERNAME(RQHD.GATE_CD, RQHD.ESTM_USER_ID, #{ses.langCd}) AS ESTM_USER_NM , RQHD.FAIL_BID_DATE , RQHD.FAIL_BID_RMK , RQHD.SETTLE_TYPE ,GETCODENAME(RQHD.GATE_CD, 'M065', RQHD.SETTLE_TYPE, #{ses.langCd}) AS SETTLE_TYPE_LOC , RQHD.AMT_TYPE ,GETCODENAME(RQHD.GATE_CD, 'M303', RQHD.AMT_TYPE, #{ses.langCd}) AS AMT_TYPE_LOC , RQHD.CUR , RQHD.VAT_TYPE , RQHD.PR_AMT , RQHD.EST_PRICE_TYPE , RQHD.RMK_TEXT_NUM , RQHD.ATT_FILE_NUM ,(CASE WHEN #{baseDataType} = 'RERFX' THEN NULL ELSE RQHD.APP_DOC_NUM END) AS APP_DOC_NUM ,(CASE WHEN #{baseDataType} = 'RERFX' THEN NULL ELSE RQHD.APP_DOC_CNT END) AS APP_DOC_CNT ,(CASE WHEN #{baseDataType} = 'RERFX' THEN NULL ELSE RQHD.SIGN_STATUS END) AS SIGN_STATUS
,(CASE WHEN #{baseDataType} = 'RERFX' THEN TO_NUMBER(RQHD.RFX_CNT) + 1 ELSE RQHD.RFX_CNT END) AS RFX_CNT
,(CASE WHEN #{baseDataType} = 'RERFX' THEN CAST(RQHD.RFX_CNT AS INT) + 1 ELSE RQHD.RFX_CNT END) AS RFX_CNT
FROM STOCRQHD RQHD WHERE RQHD.GATE_CD = #{ses.gateCd} AND RQHD.DEL_FLAG = '0' AND RQHD.BUYER_CD = #{BUYER_CD}
AND RQHD.RFX_NUM = #{RFX_NUM} AND RQHD.RFX_CNT = #{RFX_CNT}
AND RQHD.RLT_APP_DOC_NUM = #{APP_DOC_NUM} AND RQHD.RLT_APP_DOC_CNT = #{APP_DOC_CNT}

SELECT A.* ,(CASE WHEN A.HD_PROGRESS_CD IN ('2550','1300') THEN '' WHEN A.HD_PROGRESS_CD = '2500' THEN (CASE WHEN A.SETTEL_CNT = 0 THEN 'N' WHEN A.SETTEL_CNT = A.SEND_CNT THEN 'Y' WHEN (A.SETTEL_CNT > 0 AND A.SETTEL_CNT < A.SEND_CNT) THEN 'S' ELSE '' END) ELSE '' /** 선정대기(A), 탈락(N), 선정(Y), 부분선정(S) */ END) AS SETTLE_FLAG /** 20200810 : 기존 선정여부 => 낙찰여부로 변경 ,(CASE WHEN A.HD_PROGRESS_CD IN ('2550','1300') THEN 'X' ELSE (CASE WHEN A.EXEC_NUM IS NULL THEN 'A' WHEN A.SETTEL_CNT = 0 THEN 'N' WHEN A.SETTEL_CNT = A.SEND_CNT THEN 'Y' WHEN (A.SETTEL_CNT > 0 AND A.SETTEL_CNT < A.SEND_CNT) THEN 'S' ELSE 'A' END) END) AS SETTLE_FLAG*/ FROM ( SELECT DISTINCT RQHD.GATE_CD , RQHD.BUYER_CD , RQHD.PROGRESS_CD AS HD_PROGRESS_CD , QTHD.QTA_NUM ,GETCOMCODE(#{ses.gateCd}, 'M072', (CASE WHEN RQHD.RFX_END_DATE > SYSDATE THEN (RQVN.RFX_PROGRESS_CD, '100') ELSE RQVN.RFX_PROGRESS_CD END), 0, #{ses.langCd}) AS PROGRESS_CD , RQVN.VENDOR_CD ,GETVENDORNAME(RQVN.GATE_CD, RQVN.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM ,QTHD.PIC_USER_NM AS PIC_USER_NM ,QTHD.PIC_TEL_NUM AS PIC_TEL_NUM ,QTHD.PIC_EMAIL AS PIC_EMAIL ,(RQVN.RFX_RECEIPT_DATE, 'YYYY-MM-DD HH24:MI') AS RFX_RECEIPT_DATE ,(QTHD.SEND_DATE, 'YYYY-MM-DD HH24:MI') AS SEND_DATE ,(CASE WHEN RQHD.RFX_OPEN_DATE IS NOT NULL THEN QTHD.QTA_AMT ELSE NULL END) AS QTA_AMT ,(CASE WHEN RQVN.RFX_PROGRESS_CD = '150' THEN 'Y' ELSE NULL END) AS RFX_GIVEUP_FLAG , RQVN.RFX_GIVEUP_RMK ,(CASE WHEN RQHD.RFX_OPEN_DATE IS NOT NULL THEN '1' ELSE '0' END) AS RFX_OPEN_FLAG -- 개찰여부 , QTHD.VALID_TO_DATE -- 견적유효일자 , QTHD.ATT_FILE_NUM ,GETFILECOUNT(QTHD.GATE_CD, QTHD.ATT_FILE_NUM) AS ATT_FILE_CNT , QTHD.IP_ADDR ,(SELECT COUNT(*) FROM STOCQTDT QTDT WHERE QTDT.GATE_CD = QTHD.GATE_CD AND QTDT.BUYER_CD = QTHD.BUYER_CD AND QTDT.QTA_NUM = QTHD.QTA_NUM AND QTDT.DEL_FLAG = '0') AS SEND_CNT ,(SELECT COUNT(*) FROM STOCQTDT QTDT WHERE QTDT.GATE_CD = QTHD.GATE_CD AND QTDT.BUYER_CD = QTHD.BUYER_CD AND QTDT.QTA_NUM = QTHD.QTA_NUM AND QTDT.SETTLE_QT > 0 AND QTDT.DEL_FLAG = '0') AS SETTEL_CNT /** 20200810 : 기존 선정여부 => 낙찰여부로 변경 ,(SELECT MAX(CNHD.EXEC_NUM) FROM STOCCNDT CNDT INNER JOIN STOCCNHD CNHD ON (CNHD.GATE_CD = CNDT.GATE_CD AND CNHD.BUYER_CD = CNDT.BUYER_CD AND CNHD.EXEC_NUM = CNDT.EXEC_NUM AND CNHD.DEL_FLAG = '0') WHERE CNDT.GATE_CD = RQHD.GATE_CD AND CNDT.BUYER_CD = RQHD.BUYER_CD AND CNDT.RFX_NUM = RQHD.RFX_NUM AND CNDT.RFX_CNT = RQHD.RFX_CNT AND CNDT.DEL_FLAG = '0' AND CNHD.SIGN_STATUS = 'E') AS EXEC_NUM ,(SELECT COUNT(*) FROM STOCCNDT CNDT INNER JOIN STOCCNHD CNHD ON (CNHD.GATE_CD = CNDT.GATE_CD AND CNHD.BUYER_CD = CNDT.BUYER_CD AND CNHD.EXEC_NUM = CNDT.EXEC_NUM AND CNHD.DEL_FLAG = '0') WHERE CNDT.GATE_CD = QTHD.GATE_CD AND CNDT.BUYER_CD = QTHD.BUYER_CD AND CNDT.QTA_NUM = QTHD.QTA_NUM AND CNDT.DEL_FLAG = '0' AND CNHD.SIGN_STATUS = 'E') AS SETTEL_CNT */ FROM STOCRQHD RQHD JOIN STOCRQVN RQVN ON (RQVN.GATE_CD = RQHD.GATE_CD AND RQVN.BUYER_CD = RQHD.BUYER_CD AND RQVN.RFX_NUM = RQHD.RFX_NUM AND RQVN.RFX_CNT = RQHD.RFX_CNT) LEFT JOIN STOCQTHD QTHD ON( RQVN.GATE_CD = QTHD.GATE_CD AND RQVN.BUYER_CD = QTHD.BUYER_CD AND RQVN.RFX_NUM = QTHD.RFX_NUM AND RQVN.RFX_CNT = QTHD.RFX_CNT AND RQVN.VENDOR_CD = QTHD.VENDOR_CD -- 2021.02.24 제거 -- AND QTHD.LAST_FLAG = '1' AND QTHD.DEL_FLAG = '0') WHERE RQHD.GATE_CD = #{ses.gateCd} AND RQHD.BUYER_CD = #{BUYER_CD}
AND RQHD.RFX_NUM = #{RFX_NUM} AND RQHD.RFX_CNT = #{RFX_CNT}
AND RQHD.RLT_APP_DOC_NUM = #{APP_DOC_NUM} AND RQHD.RLT_APP_DOC_CNT = #{APP_DOC_CNT}
AND RQHD.DEL_FLAG = '0' AND RQVN.DEL_FLAG = '0' AND (CASE WHEN RQHD.RFX_END_DATE > SYSDATE THEN (RQVN.RFX_PROGRESS_CD, '100') ELSE CASE WHEN RQVN.RFX_PROGRESS_CD = '150' THEN RQVN.RFX_PROGRESS_CD ELSE '400' END END) IS NOT NULL ) A WHERE 1 = 1 ORDER BY A.SEND_DATE ASC

		SELECT ((RFX_OPEN_DATE, 'yyyyMMdd'), '-')
		FROM STOCRQHD
         WHERE GATE_CD  = #{ses.gateCd}
           AND BUYER_CD = #{BUYER_CD}
           AND RFX_NUM  = #{RFX_NUM}
           AND RFX_CNT  = #{RFX_CNT}

