             GETRFQOPENSTATUS(PROGRESS_CD, RFX_END_DATE) AS RFQ_OPEN
          FROM STOCRQHD
         WHERE GATE_CD  = #{ses.gateCd}
           AND BUYER_CD = #{BUYER_CD}
           AND RFX_NUM  = #{RFX_NUM}
           AND RFX_CNT  = #{RFX_CNT}
           AND DEL_FLAG = '0'

